from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismCreateEntityNode(BaseNode):
    name = "Prism: Create Entity"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity_type", "string", widget_type="dropdown", options=["asset","shot"], default="asset")
        self.add_input("asset_path", "string", widget_type="text", default="chars/dog")
        self.add_input("sequence", "string", widget_type="text", default="a")
        self.add_input("shot", "string", widget_type="text", default="0010")
        self.add_output("success", "bool")
        self.add_output("entity", "dict")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'success': False, 'entity': {}}
        etype = inputs.get('entity_type') or 'asset'
        if etype == 'asset':
            entity = {
                'type': 'asset',
                'asset_path': inputs.get('asset_path') or '',
                'path': '',
            }
        else:
            entity = {
                'type': 'shot',
                'sequence': inputs.get('sequence') or '',
                'shot': inputs.get('shot') or '',
                'path': '',
                'location': '',
                'paths': {},
            }
        try:
            result = core.entities.createEntity(entity)
            # Merge returned entity data (path etc.) if Prism returns a dict
            if isinstance(result, dict):
                entity.update({k: v for k, v in result.items() if v is not None})
            self.log_success(f"Created entity: {entity}")
            await self.set_output('exec_out', True)
            return {'success': True, 'entity': entity}
        except Exception as e:
            self.log_error(f"createEntity failed: {e}")
            return {'success': False, 'entity': entity}

def register_node():
    return PrismCreateEntityNode
